9	export async function callApi(action: string, payload: Record<string, unknown> = {}): Promise<Record<string, unknown>> {
10	  const body = JSON.stringify({ action, ...payload });
11	
12	  const res = await fetch(config.agentApiUrl, {
13	    method: "POST",
14	    headers: {
15	      "Content-Type": "application/json",
16	      "x-agent-key": config.agentKey,
17	    },
18	    body,
19	  });
20	
21	  if (!res.ok) {
22	    const text = await res.text();
23	    throw new Error(`agent-api ${action} returned ${res.status}: ${text}`);
24	  }
25	
26	  const data = await res.json();
27	  if (data && !data.ok) {
28	    throw new Error(`agent-api ${action} error: ${data.error || "unknown"}`);
29	  }
30	  return data;
31	}
