219	export async function pair(
220	  pairingCode: string,
221	  agentName: string,
222	): Promise<{ agent_id: string; agent_key: string }> {
223	  const maskedCode = pairingCode.length > 4
224	    ? `${pairingCode.slice(0, 4)}-****-****-****`
225	    : "****";
226	  const endpoint = config.agentApiUrl;
227	
228	  logger.info("Attempting pairing", { endpoint, pairingCode: maskedCode });
229	
230	  let res: Response;
231	  try {
232	    res = await fetch(endpoint, {
233	      method: "POST",
234	      headers: { "Content-Type": "application/json" },
235	      body: JSON.stringify({
236	        action: "pair",
237	        pairing_code: pairingCode,
238	        agent_name: agentName,
239	      }),
240	    });
241	  } catch (fetchErr) {
242	    const msg = (fetchErr as Error).message;
243	    logger.error("Pairing fetch failed (network-level error)", {
244	      endpoint,
245	      error: msg,
246	      stack: (fetchErr as Error).stack,
247	    });
248	    throw new Error(`Pairing network error: ${msg}`);
249	  }
250	
251	  logger.info("Pairing response received", {
252	    status: res.status,
253	    statusText: res.statusText,
254	    contentType: res.headers.get("content-type"),
255	  });
256	
257	  // Read raw body first to handle non-JSON responses
258	  let rawBody: string;
259	  try {
260	    rawBody = await res.text();
261	  } catch (readErr) {
262	    throw new Error(`Pairing failed: could not read response body (HTTP ${res.status})`);
263	  }
264	
265	  if (!res.ok) {
266	    logger.error("Pairing HTTP error", {
267	      status: res.status,
268	      statusText: res.statusText,
269	      body: rawBody.slice(0, 500),
270	    });
271	    // Try to parse JSON error message
272	    try {
273	      const errData = JSON.parse(rawBody);
274	      throw new Error(errData.error || `Pairing failed with HTTP ${res.status}`);
275	    } catch (parseErr) {
276	      if ((parseErr as Error).message.startsWith("Pairing")) throw parseErr;
277	      throw new Error(`Pairing failed with HTTP ${res.status}: ${rawBody.slice(0, 200)}`);
278	    }
279	  }
280	
281	  let data: Record<string, unknown>;
282	  try {
283	    data = JSON.parse(rawBody);
284	  } catch {
285	    logger.error("Pairing response is not valid JSON", {
286	      status: res.status,
287	      body: rawBody.slice(0, 500),
288	    });
289	    throw new Error(`Pairing failed: response is not JSON (HTTP ${res.status})`);
290	  }
291	
292	  if (!data.ok) {
293	    logger.error("Pairing rejected by server", {
294	      error: data.error,
295	      fullResponse: rawBody.slice(0, 500),
296	    });
297	    throw new Error(
298	      (data.error as string) || `Pairing rejected by server (no error message in response)`
299	    );
300	  }
301	
302	  logger.info("Pairing succeeded", {
303	    agentId: data.agent_id,
304	    agentType: data.agent_type,
305	  });
306	  return { agent_id: data.agent_id as string, agent_key: data.agent_key as string };
307	}
