1	/**
2	 * PDF Text Sampler (Windows Agent)
3	 *
4	 * Reads each PDF asset from the NAS and extracts text using a cascade:
5	 *
6	 *   1. mupdf  — native text extraction (primary; robust C library)
7	 *   2. OCR    — tesseract.js on a mupdf-rendered page image (scanned PDFs)
8	 *   3. AI     — vision model from PDF_EXTRACTION_CONFIG/AI_MODELS catalog
9	 *
10	 * Reports per-file progress back to the cloud so the UI shows real-time status.
11	 */
12	
13	import { readFile } from "node:fs/promises";
14	import { join } from "node:path";
15	import { logger } from "./logger";
16	import * as api from "./api-client";
17	import { uploadPdfPage } from "./uploader";
18	
19	// OTA-safe: mupdf, tesseract.js, and @anthropic-ai/sdk are only available after
20	// a full installer run, not OTA dist updates. Load them lazily inside the function.
21	// eslint-disable-next-line @typescript-eslint/no-explicit-any
22	const dynamicImport = new Function("m", "return import(m)") as (m: string) => Promise<any>;
23	
24	// eslint-disable-next-line @typescript-eslint/no-explicit-any
25	function tryRequire(mod: string): any | null {
26	  try {
27	    // eslint-disable-next-line @typescript-eslint/no-require-imports
28	    return require(mod);
29	  } catch {
30	    return null;
31	  }
32	}
33	
34	export interface PdfSampleAsset {
35	  id: string;
36	  relative_path: string;
37	  filename: string;
38	}
39	
40	export interface AiModelDef {
41	  id: string;
42	  provider: string;
43	  apiModel: string;
44	  capabilities: string[];
45	}
46	
47	export interface AiConfig {
48	  models: AiModelDef[];
49	  pdf_extraction: { ai_vision_model_id: string } | null;
50	  googleApiKey: string;
51	  anthropicApiKey: string;
52	  /** OpenRouter API key — if set, all AI vision calls go through openrouter.ai */
53	  openRouterApiKey?: string;
54	  /** Per-task model overrides from AI_TASK_MODELS admin config */
55	  aiTaskModels?: Record<string, string>;
56	}
57	
58	export interface PdfTextSampleResult {
59	  asset_id: string;
60	  filename: string;
61	  relative_path: string;
62	  extraction_method: "pdf_text" | "likely_scanned" | "failed" | "ocr_text" | "ai_vision";
63	  extracted_text: string | null;
64	  page_count: number | null;
65	  char_count: number;
66	  extraction_error: string | null;
67	  thumbnail_url?: string;
68	}
