78	// ── AI vision call ────────────────────────────────────────────────────────────
79	
80	const PDF_EXTRACTION_PROMPT = "Extract all text from this document page. Return only the raw extracted text with no commentary.";
81	
82	async function callAiVision(pngBuffer: Buffer, aiConfig: AiConfig): Promise<string> {
83	  const base64 = pngBuffer.toString("base64");
84	
85	  // ── Path 1: OpenRouter (preferred when key is configured) ───────────────
86	  if (aiConfig.openRouterApiKey) {
87	    const model = aiConfig.aiTaskModels?.pdf_extraction ?? "google/gemini-2.0-flash-001";
88	    const res = await fetch("https://openrouter.ai/api/v1/chat/completions", {
89	      method: "POST",
90	      headers: {
91	        "Authorization": `Bearer ${aiConfig.openRouterApiKey}`,
92	        "Content-Type": "application/json",
93	      },
94	      signal: AbortSignal.timeout(60_000),
95	      body: JSON.stringify({
96	        model,
97	        messages: [{
98	          role: "user",
99	          content: [
100	            { type: "image_url", image_url: { url: `data:image/png;base64,${base64}` } },
101	            { type: "text", text: PDF_EXTRACTION_PROMPT },
102	          ],
103	        }],
104	      }),
105	    });
106	    if (!res.ok) {
107	      const errText = await res.text();
108	      throw new Error(`OpenRouter API ${res.status}: ${errText.slice(0, 200)}`);
109	    }
110	    // eslint-disable-next-line @typescript-eslint/no-explicit-any
111	    const data = await res.json() as any;
112	    return ((data?.choices?.[0]?.message?.content as string) ?? "").trim();
113	  }
114	
115	  // ── Path 2: Legacy direct API (backward compat when no OpenRouter key) ──
116	  const modelId = aiConfig.pdf_extraction?.ai_vision_model_id;
117	  if (!modelId) return "";
118	
119	  const modelDef = aiConfig.models.find((m) => m.id === modelId);
120	  if (!modelDef) {
121	    logger.warn("PDF text sample: ai vision model not found in catalog", { modelId });
122	    return "";
123	  }
124	  if (!modelDef.capabilities.includes("vision")) {
125	    logger.warn("PDF text sample: selected model has no vision capability", { modelId });
126	    return "";
127	  }
128	
129	  if (modelDef.provider === "google") {
130	    if (!aiConfig.googleApiKey) {
131	      logger.warn("PDF text sample: GOOGLE_AI_API_KEY not configured");
132	      return "";
133	    }
134	    const url = `https://generativelanguage.googleapis.com/v1beta/models/${modelDef.apiModel}:generateContent?key=${aiConfig.googleApiKey}`;
135	    const res = await fetch(url, {
136	      method: "POST",
137	      headers: { "Content-Type": "application/json" },
138	      signal: AbortSignal.timeout(60_000),
139	      body: JSON.stringify({
140	        contents: [{
141	          role: "user",
142	          parts: [
143	            { inlineData: { mimeType: "image/png", data: base64 } },
144	            { text: PDF_EXTRACTION_PROMPT },
145	          ],
146	        }],
147	      }),
148	    });
149	    if (!res.ok) {
150	      const errText = await res.text();
151	      throw new Error(`Gemini API ${res.status}: ${errText.slice(0, 200)}`);
152	    }
153	    // eslint-disable-next-line @typescript-eslint/no-explicit-any
154	    const data = await res.json() as any;
155	    return (data?.candidates?.[0]?.content?.parts?.[0]?.text as string || "").trim();
156	
157	  } else if (modelDef.provider === "anthropic") {
158	    if (!aiConfig.anthropicApiKey) {
159	      logger.warn("PDF text sample: ANTHROPIC_API_KEY not configured");
160	      return "";
161	    }
162	    const AnthropicLib = tryRequire("@anthropic-ai/sdk");
163	    if (!AnthropicLib) throw new Error("@anthropic-ai/sdk not installed");
164	    const Anthropic = AnthropicLib.default ?? AnthropicLib;
165	    const anthropic = new Anthropic({ apiKey: aiConfig.anthropicApiKey });
166	    const aiResponse = await anthropic.messages.create({
167	      model: modelDef.apiModel,
168	      max_tokens: 2048,
169	      messages: [{
170	        role: "user",
171	        content: [
172	          { type: "image", source: { type: "base64", media_type: "image/png", data: base64 } },
173	          { type: "text", text: PDF_EXTRACTION_PROMPT },
174	        ],
175	      }],
176	    });
177	    // eslint-disable-next-line @typescript-eslint/no-explicit-any
178	    const first = aiResponse.content[0] as any;
179	    return (first?.type === "text" ? (first.text as string) : "").trim();
180	  }
181	
182	  logger.warn("PDF text sample: unsupported ai vision provider", { provider: modelDef.provider });
183	  return "";
184	}
