187	
188	async function reportProgress(
189	  processed: number,
190	  total: number,
191	  currentFile: string | null,
192	  currentStep: string | null,
193	  fileResults: FileProgressEntry[],
194	  error?: string,
195	): Promise<void> {
196	  try {
197	    await api.reportPdfTextSampleProgress({
198	      processed,
199	      total,
200	      current_file: currentFile,
201	      current_step: currentStep,
202	      file_results: fileResults.slice(-25), // keep last 25 for UI
203	      ...(error ? { error } : {}),
204	    });
