212	// ── Process a single PDF ─────────────────────────────────────────────────────
213	
214	async function processSinglePdf(
215	  asset: PdfSampleAsset,
216	  fullPath: string,
217	  aiConfig: AiConfig,
218	  index: number,
219	  total: number,
220	  fileResults: FileProgressEntry[],
221	): Promise<PdfTextSampleResult> {
222	  // Report: starting this file
223	  await reportProgress(index, total, asset.filename, "reading", fileResults);
224	
225	  const buffer = await readFile(fullPath);
226	
227	  let rawText = "";
228	  let numPages: number | null = null;
229	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
230	  let mupdfRef: any = null;
231	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
232	  let mupdfDoc: any = null;
233	
234	  // ── Step 1: mupdf text extraction ───────────────────────────────────
235	  await reportProgress(index, total, asset.filename, "mupdf", fileResults);
236	  try {
237	    mupdfRef = await dynamicImport("mupdf").catch(() => null);
238	    if (!mupdfRef) throw new Error("mupdf not installed");
239	    mupdfDoc = mupdfRef.Document.openDocument(buffer, "application/pdf");
240	    numPages = mupdfDoc.countPages();
241	    const parts: string[] = [];
242	    for (let p = 0; p < (numPages ?? 0); p++) {
243	      parts.push(mupdfDoc.loadPage(p).toStructuredText("preserve-whitespace").asText());
244	    }
245	    rawText = parts.join("\n");
246	  } catch (mupdfErr) {
247	    logger.warn("PDF text sample: mupdf text extraction failed", {
248	      filename: asset.filename,
249	      error: (mupdfErr as Error).message,
250	    });
251	  }
252	
253	  const text = rawText.trim();
254	  const charCount = text.length;
255	
256	  if (charCount >= 100) {
257	    logger.info("PDF text sample: extracted via mupdf text", {
258	      filename: asset.filename, chars: charCount, pages: numPages,
259	    });
260	    return {
261	      asset_id: asset.id, filename: asset.filename, relative_path: asset.relative_path,
262	      extraction_method: "pdf_text", extracted_text: text,
263	      page_count: numPages, char_count: charCount, extraction_error: null,
264	    };
265	  }
266	
267	  // ── Step 2: render page 0 to PNG ────────────────────────────────────
268	  await reportProgress(index, total, asset.filename, "rendering", fileResults);
269	  let pngBuffer: Buffer | null = null;
270	  let thumbnailUrl: string | undefined;
271	  try {
272	    if (!mupdfRef) mupdfRef = await dynamicImport("mupdf").catch(() => null);
273	    if (mupdfRef) {
274	      if (!mupdfDoc) {
275	        mupdfDoc = mupdfRef.Document.openDocument(buffer, "application/pdf");
276	        numPages = mupdfDoc.countPages();
277	      }
278	      const page = mupdfDoc.loadPage(0);
279	      // eslint-disable-next-line @typescript-eslint/no-explicit-any
280	      const pixmap = page.toPixmap([2, 0, 0, 2, 0, 0] as any, mupdfRef.ColorSpace.DeviceRGB, false);
281	      pngBuffer = Buffer.from(pixmap.asPNG() as Uint8Array);
282	      try {
283	        thumbnailUrl = await uploadPdfPage(asset.id, 0, pngBuffer);
284	      } catch (uploadErr) {
285	        logger.warn("PDF text sample: thumbnail upload failed (non-fatal)", {
286	          filename: asset.filename, error: (uploadErr as Error).message,
287	        });
288	      }
289	    }
290	  } catch (renderErr) {
291	    logger.warn("PDF text sample: mupdf page render failed", {
292	      filename: asset.filename, error: (renderErr as Error).message,
293	    });
294	  }
295	
296	  // ── Step 3: OCR via tesseract.js ────────────────────────────────────
297	  let ocrText = "";
298	  if (pngBuffer) {
299	    await reportProgress(index, total, asset.filename, "ocr", fileResults);
300	    try {
301	      // eslint-disable-next-line @typescript-eslint/no-explicit-any
302	      const tesseractLib: any = await dynamicImport("tesseract.js").catch(() => null);
303	      if (!tesseractLib) throw new Error("tesseract.js not installed");
304	      const worker = await tesseractLib.createWorker("eng");
305	      const ocrResult = await worker.recognize(pngBuffer);
306	      await worker.terminate();
307	      ocrText = (ocrResult.data.text as string).trim();
308	    } catch (ocrErr) {
309	      logger.warn("PDF text sample: OCR failed", {
310	        filename: asset.filename, error: (ocrErr as Error).message,
311	      });
312	    }
313	  }
314	
315	  if (ocrText.length >= 100) {
316	    logger.info("PDF text sample: extracted via OCR", {
317	      filename: asset.filename, chars: ocrText.length,
318	    });
319	    return {
320	      asset_id: asset.id, filename: asset.filename, relative_path: asset.relative_path,
321	      extraction_method: "ocr_text", extracted_text: ocrText,
322	      page_count: numPages, char_count: ocrText.length, extraction_error: null,
323	      thumbnail_url: thumbnailUrl,
324	    };
325	  }
326	
327	  // ── Step 4: AI vision ───────────────────────────────────────────────
328	  let aiText = "";
329	  let aiErrMsg = "";
330	  if (pngBuffer) {
331	    await reportProgress(index, total, asset.filename, "ai_vision", fileResults);
332	    try {
333	      aiText = await callAiVision(pngBuffer, aiConfig);
334	    } catch (aiErr) {
335	      aiErrMsg = (aiErr as Error).message;
336	      logger.warn("PDF text sample: AI vision failed", {
337	        filename: asset.filename, error: aiErrMsg,
338	      });
339	    }
340	  }
341	
342	  if (aiText.length > 0) {
343	    logger.info("PDF text sample: extracted via AI vision", {
344	      filename: asset.filename, chars: aiText.length,
345	    });
346	    return {
347	      asset_id: asset.id, filename: asset.filename, relative_path: asset.relative_path,
348	      extraction_method: "ai_vision", extracted_text: aiText,
349	      page_count: numPages, char_count: aiText.length, extraction_error: null,
350	      thumbnail_url: thumbnailUrl,
351	    };
352	  }
353	
354	  const finalText = ocrText.length > 0 ? ocrText : text;
355	  const finalCount = finalText.length;
356	  const method: "pdf_text" | "likely_scanned" | "failed" =
357	    finalCount >= 100 ? "pdf_text" : finalCount > 0 ? "likely_scanned" : "failed";
358	
359	  return {
360	    asset_id: asset.id, filename: asset.filename, relative_path: asset.relative_path,
361	    extraction_method: method,
362	    extracted_text: finalCount > 0 ? finalText : null,
363	    page_count: numPages, char_count: finalCount,
364	    extraction_error: aiErrMsg ? aiErrMsg.slice(0, 500) : null,
365	    thumbnail_url: thumbnailUrl,
366	  };
367	}
368	
369	// ── Main sampler ──────────────────────────────────────────────────────────────
370	
371	export async function runPdfTextSample(
372	  assets: PdfSampleAsset[],
373	  mountRoot: string,
374	  aiConfig: AiConfig,
375	): Promise<void> {
376	  if (assets.length === 0) {
377	    logger.info("PDF text sample: no assets to process");
378	    return;
379	  }
380	
381	  logger.info("PDF text sample: starting", { count: assets.length, mountRoot });
382	
383	  const results: PdfTextSampleResult[] = [];
384	  const fileResults: FileProgressEntry[] = [];
385	
386	  // Report initial pickup
387	  await reportProgress(0, assets.length, null, "starting", []);
388	
389	  for (let i = 0; i < assets.length; i++) {
390	    const asset = assets[i];
391	    const fullPath = join(mountRoot, asset.relative_path);
392	
393	    try {
394	      const result = await processSinglePdf(asset, fullPath, aiConfig, i, assets.length, fileResults);
395	      results.push(result);
396	      fileResults.push({
397	        filename: asset.filename,
398	        status: result.extraction_method === "failed" ? "failed" : "success",
399	        method: result.extraction_method,
400	        chars: result.char_count,
401	        error: result.extraction_error ?? undefined,
402	      });
403	    } catch (e) {
404	      const errMsg = (e as Error).message;
405	      logger.warn("PDF text sample: extraction failed", {
406	        filename: asset.filename, path: fullPath, error: errMsg,
407	      });
408	      results.push({
409	        asset_id: asset.id, filename: asset.filename, relative_path: asset.relative_path,
410	        extraction_method: "failed", extracted_text: null,
411	        page_count: null, char_count: 0, extraction_error: errMsg.slice(0, 500),
412	      });
413	      fileResults.push({
414	        filename: asset.filename, status: "failed", method: "failed", chars: 0, error: errMsg.slice(0, 200),
415	      });
416	    }
417	
418	    // Report progress after each file
419	    await reportProgress(i + 1, assets.length, null, "done", fileResults);
420	  }
421	
422	  try {
423	    await api.completePdfTextSample(results);
424	    logger.info("PDF text sample: completed", { total: results.length });
425	  } catch (e) {
426	    logger.error("PDF text sample: failed to submit results", { error: (e as Error).message });
427	    // Report the error so UI shows it
428	    await reportProgress(results.length, assets.length, null, "done", fileResults, (e as Error).message);
429	  }
430	}
